using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainerService>();
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>();

var app = builder.Build();

// Train the model at startup and register it with the prediction pool
var trainer = app.Services.GetRequiredService<ModelTrainerService>();
trainer.TrainAndSave();
app.Services.GetRequiredService<Microsoft.Extensions.ML.PredictionEnginePool<TicketInput, TicketPrediction>>();

// Reconfigure the pool to load the trained model
builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainerService>();
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

app = builder.Build();

// Re-train (quick, uses cached data) to ensure model is fresh
var trainer2 = app.Services.GetRequiredService<ModelTrainerService>();
trainer2.TrainAndSave();

app.MapControllers();
app.Run();

