using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class ModelTrainerService
{
    public static string[] TrainAndSave(string dataPath, string modelPath, ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        logger.LogInformation("Loading training data from {DataPath}", dataPath);
        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(mlContext)
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on the test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        logger.LogInformation("=== Model Evaluation Metrics ===");
        logger.LogInformation("Macro Accuracy:     {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("Micro Accuracy:     {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("Log Loss:           {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", metrics.LogLossReduction);
        logger.LogInformation("Confusion Matrix:\n{ConfusionMatrix}",
            metrics.ConfusionMatrix.GetFormattedConfusionTable());

        Directory.CreateDirectory(Path.GetDirectoryName(modelPath)!);
        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {ModelPath}", modelPath);

        // Extract label ordering from the trained model's Score column metadata
        var outputSchema = model.GetOutputSchema(data.Schema);
        var scoreColumn = outputSchema["Score"];
        var slotNames = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        logger.LogInformation("Label order: {Labels}", string.Join(", ", labels));
        return labels;
    }
}

