using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train model at startup
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

string[] labelNames;
using (var loggerFactory = LoggerFactory.Create(b => b.AddConsole()))
{
    labelNames = ModelTrainerService.TrainAndSave(dataPath, modelPath,
        loggerFactory.CreateLogger("ModelTrainer"));
}

// Register label order and thread-safe prediction pool
builder.Services.AddSingleton(new LabelMetadata(labelNames));
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

